// === CUSTOM LOG CATEGORY ===
// MyGame.h
DECLARE_LOG_CATEGORY_EXTERN(LogMyGame, Log, All);

// MyGame.cpp
DEFINE_LOG_CATEGORY(LogMyGame);

// === USAGE ===
// Basic logging
UE_LOG(LogMyGame, Display, TEXT("Player spawned at %s"), *GetActorLocation().ToString());

// Warning
UE_LOG(LogMyGame, Warning, TEXT("Health is low: %f"), Health);

// Error
UE_LOG(LogMyGame, Error, TEXT("Failed to load save file: %s"), *SlotName);

// With FString
FString PlayerName = TEXT("Hero");
UE_LOG(LogMyGame, Log, TEXT("Player name: %s"), *PlayerName);

// With FName
FName ItemID = TEXT("Sword_01");
UE_LOG(LogMyGame, Log, TEXT("Picked up: %s"), *ItemID.ToString());

// On-screen debug message (visible in viewport)
if (GEngine) {
    GEngine->AddOnScreenDebugMessage(-1, 5.f, FColor::Green,
        FString::Printf(TEXT("Health: %f"), Health));
}

// Conditional logging (only first time)
UE_LOG(LogMyGame, Log, TEXT("This only logs once per session"));

// === FILTERING IN EDITOR ===
// Output Log > type 'LogMyGame' in the filter to see only your category

// === ON-SCREEN DEBUG MESSAGES ===

// New message each call (stacks on screen)
if (GEngine) {
    GEngine->AddOnScreenDebugMessage(-1, 3.f, FColor::Yellow,
        TEXT("Damage applied!"));
}

// Overwrite same slot (Key=1) — perfect for Tick
void AMyActor::Tick(float DeltaTime) {
    Super::Tick(DeltaTime);
    if (GEngine) {
        GEngine->AddOnScreenDebugMessage(1, 0.f, FColor::Cyan,
            FString::Printf(TEXT("Speed: %.1f"), GetVelocity().Size()));
        GEngine->AddOnScreenDebugMessage(2, 0.f, FColor::Green,
            FString::Printf(TEXT("Health: %.0f / %.0f"), Health, MaxHealth));
    }
}

// 3D world-space debug text
DrawDebugString(GetWorld(), GetActorLocation() + FVector(0, 0, 100),
    FString::Printf(TEXT("HP: %.0f"), Health), nullptr, FColor::White, 0.f);

// Strip from shipping builds
#if !UE_BUILD_SHIPPING
    if (GEngine) {
        GEngine->AddOnScreenDebugMessage(-1, 5.f, FColor::Red, TEXT("Debug mode active"));
    }
#endif

// === VISUAL DEBUGGING EXAMPLES ===
#include "DrawDebugHelpers.h"

// Visualize a line trace
FHitResult Hit;
FVector Start = GetActorLocation();
FVector End = Start + GetActorForwardVector() * 1000.f;

bool bHit = GetWorld()->LineTraceSingleByChannel(Hit, Start, End, ECC_Visibility);

// Draw the trace
DrawDebugLine(GetWorld(), Start, bHit ? Hit.ImpactPoint : End,
    bHit ? FColor::Red : FColor::Green, false, 2.f, 0, 1.f);

// Draw hit point
if (bHit) {
    DrawDebugSphere(GetWorld(), Hit.ImpactPoint, 10.f, 12, FColor::Red, false, 2.f);
    DrawDebugArrow(GetWorld(), Hit.ImpactPoint,
        Hit.ImpactPoint + Hit.ImpactNormal * 50.f, 10.f, FColor::Blue, false, 2.f);
}

// Visualize damage radius
DrawDebugSphere(GetWorld(), ExplosionCenter, DamageRadius, 24,
    FColor::Orange, false, 3.f);

// Visualize AI perception cone
DrawDebugCone(GetWorld(), EyeLocation, ForwardVector, SightRange,
    FMath::DegreesToRadians(PeripheralAngle), FMath::DegreesToRadians(PeripheralAngle),
    12, FColor::Yellow, false, 0.f);

// Visualize forward direction as arrow
DrawDebugArrow(GetWorld(), GetActorLocation(),
    GetActorLocation() + GetActorForwardVector() * 200.f,
    20.f, FColor::Red, false, 0.f, 0, 2.f);

// === VISUAL LOGGER ===
#include "VisualLogger/VisualLogger.h"

void AAIEnemy::UpdateBehavior() {
    // Log text to Visual Logger
    UE_VLOG(this, LogAI, Log, TEXT("Current state: %s, Target: %s"),
        *StateToString(CurrentState),
        *GetNameSafe(CurrentTarget));

    // Log a location marker
    UE_VLOG_LOCATION(this, LogAI, Log, GetActorLocation(), 50.f,
        FColor::Green, TEXT("AI Position"));

    // Log a segment (line)
    if (CurrentTarget) {
        UE_VLOG_SEGMENT(this, LogAI, Log, GetActorLocation(),
            CurrentTarget->GetActorLocation(), FColor::Red, TEXT("To Target"));
    }
}

// === GAMEPLAY DEBUGGER ===
// No code needed for built-in categories!
// Just press ' during PIE and click on an AI actor.
// 
// For custom categories:
// 1. Subclass UGameplayDebuggerCategory
// 2. Override CollectData() and DrawData()
// 3. Register in your module's StartupModule():
//    IGameplayDebugger::Get().RegisterCategory(
//        "MyCategory",
//        IGameplayDebugger::FOnGetCategory::CreateStatic(
//            &FMyDebugCategory::MakeInstance),
//        EGameplayDebuggerCategoryState::EnabledInGameAndSimulate, 5);

// === COMMON CONSOLE COMMANDS ===
// Performance:
//   stat fps          — show FPS counter
//   stat unit         — show Game/Draw/GPU frame times (MOST USEFUL)
//   stat unitgraph    — graph of frame times over time
//   stat scenerendering — draw calls, triangles, render passes
//   stat rhi          — GPU stats
//   stat memory       — memory breakdown
//   stat particles    — particle system stats
//   stat startfile / stat stopfile — capture profiling data
//
// Visualization:
//   show collision    — render collision shapes
//   show navigation   — render NavMesh
//   show bounds       — render actor bounding boxes
//   viewmode wireframe / lit / unlit / shadercomplexity
//
// Gameplay:
//   slomo 0.25        — quarter speed (slow-mo)
//   pause             — pause the game
//   god               — invincibility
//   fly / walk / ghost — movement modes
//
// === CUSTOM CONSOLE COMMAND (C++) ===
// On your PlayerController:
UFUNCTION(Exec)
void SetHealth(float NewHealth) {
    if (AMyCharacter* Char = Cast<AMyCharacter>(GetPawn())) {
        Char->Health = NewHealth;
        UE_LOG(LogMyGame, Log, TEXT("Health set to %f"), NewHealth);
    }
}
// Now type in console: SetHealth 999
